#include <string.h>
#include <stdlib.h>
#include <stdint.h>
#include "amp.h"
static uint32_t
read_u32_be(char *buf) {
  uint32_t n = 0;
  n |= buf[0] << 24;
  n |= buf[1] << 16;
  n |= buf[2] << 8;
  n |= buf[3];
  return n;
}
static void
write_u32_be(char *buf, uint32_t n) {
  buf[0] = n >> 24 & 0xff;
  buf[1] = n >> 16 & 0xff;
  buf[2] = n >> 8 & 0xff;
  buf[3] = n & 0xff;
}
void
amp_decode(amp_t *msg, char *buf) {
  msg->version = buf[0] >> 4;
  msg->argc = buf[0] & 0xf;
  msg->buf = buf + 1;
}
char *
amp_decode_arg(amp_t *msg) {
  uint32_t len = read_u32_be(msg->buf);
  msg->buf += 4;
  char *buf = malloc(len);
  if (!buf) return NULL;
  memcpy(buf, msg->buf, len);
  msg->buf += len;
  return buf;
}
char *
amp_encode(char **argv, int argc) {
  size_t len = 1;
  size_t lens[argc];

  for (int i = 0; i < argc; ++i) {
    len += 4;
    lens[i] = strlen(argv[i]);
    len += lens[i];
  }

  char *buf = malloc(len);
  char *ret = buf;
  if (!buf) return NULL;

  *buf++ = AMP_VERSION << 4 | argc;

  for (int i = 0; i < argc; ++i) {
    size_t len = lens[i];
    write_u32_be(buf, len);
    buf += 4;
    memcpy(buf, argv[i], len);
    buf += len;
  }
  return ret;
}```

